import React, { useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { fetchAdById, clearCurrentItem } from '../store/adsSlice';
import { useAppDispatch, useAppSelector } from '../store/hooks';
import { Form, Input, InputNumber, Select, Button, Spin, Alert, Layout, Space, message, Row, Col } from 'antd';
import { ItemsAPI } from '../services/api';
import type { ItemUpdateIn } from '../types';
import { AIDescriptionButton } from '../components/AI/AIDescriptionButton';
import { AIPriceButton } from '../components/AI/AIPriceButton';
import styles from './ItemEditPage.module.css';

const { Content } = Layout;
const { Option } = Select;
const { TextArea } = Input;

const ItemEditPage: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const dispatch = useAppDispatch();
  const [form] = Form.useForm();

  const { currentItem, currentItemLoading, currentItemError } = useAppSelector((state) => state.ads);
  const category = Form.useWatch('category', form);
  const description = Form.useWatch('description', form);
  const isDescriptionEmpty = !description || description.trim() === '';

  // Draft Key
  const draftKey = `draft_ad_${id}`;

  useEffect(() => {
    if (id) {
      dispatch(fetchAdById(id));
    }
    return () => {
      dispatch(clearCurrentItem());
    };
  }, [id, dispatch]);

  useEffect(() => {
    if (currentItem) {
      const draft = localStorage.getItem(draftKey);
      if (draft) {
        try {
          const parsed = JSON.parse(draft);
          form.setFieldsValue(parsed);
          message.info('Восстановлен несохранённый черновик');
        } catch {
          form.setFieldsValue(currentItem);
        }
      } else {
        form.setFieldsValue(currentItem);
      }
    }
  }, [currentItem, form, draftKey]);

  const onValuesChange = (_: unknown, allValues: Record<string, unknown>) => {
    localStorage.setItem(draftKey, JSON.stringify(allValues));
  };

  const onFinish = async (values: ItemUpdateIn) => {
    // Clean up values before sending to API
    const payload = JSON.parse(JSON.stringify(values));
    if (payload.params) {
      const p = payload.params;
      // Remove empty strings so Zod doesn't fail on .nonempty()
      Object.keys(p).forEach(key => {
        if (p[key] === "" || p[key] === null || p[key] === undefined) {
          delete p[key];
        } else if (['yearOfManufacture', 'mileage', 'enginePower', 'area', 'floor'].includes(key)) {
          // Convert string numbers from older DB records to actual numbers for Zod schema
          p[key] = Number(p[key]);
        }
      });
    }

    try {
      await ItemsAPI.updateItem(id!, payload);
      localStorage.removeItem(draftKey);
      message.success('Объявление успешно сохранено');
      navigate(`/ads/${id}`);
    } catch (e: unknown) {
      const err = e as { response?: { data?: { message?: string, error?: any } } };
      console.error("Save error:", err.response?.data);
      const apiErr = err.response?.data?.error;
      const msg = typeof apiErr === 'object' ? JSON.stringify(apiErr) : (err.response?.data?.message || 'Ошибка');
      message.error(msg || 'Ошибка при сохранении объявления');
    }
  };

  const currentCategory = category || currentItem?.category;

  if (currentItemLoading || (!currentItem && !currentItemError)) {
    return <div className={styles.spinner}><Spin size="large" /></div>;
  }

  if (currentItemError) {
    return (
      <div style={{ padding: 24 }}>
        <Alert type="error" message="Ошибка" description={currentItemError} />
        <Button style={{ marginTop: 16 }} onClick={() => navigate('/ads')}>Назад</Button>
      </div>
    );
  }

  return (
    <Content>
      <h2>Редактирование объявления</h2>

      <Form
        form={form}
        layout="vertical"
        onFinish={onFinish}
        onValuesChange={onValuesChange}
        className={styles.form}
      >
        <Form.Item 
          name="category" 
          label="Категория" 
          rules={[{ required: true, message: 'Пожалуйста, выберите категорию' }]}
        >
          <Select>
            <Option value="auto">Авто</Option>
            <Option value="real_estate">Недвижимость</Option>
            <Option value="electronics">Электроника</Option>
          </Select>
        </Form.Item>

        <Form.Item 
          name="title" 
          label="Название объявления" 
          rules={[{ required: true, message: 'Название обов\'язково' }]}
        >
          <Input />
        </Form.Item>

        <div style={{ display: 'flex', gap: '16px', alignItems: 'flex-start' }}>
          <Form.Item 
            name="price" 
            label="Цена (₽)" 
            rules={[{ required: true, message: 'Укажите цену' }]}
            style={{ flex: 1, marginBottom: 24 }}
          >
            <InputNumber style={{ width: '100%' }} min={0} />
          </Form.Item>
          <div style={{ paddingTop: 30 }}>
            <AIPriceButton form={form} onApplyPrice={(price) => form.setFieldsValue({ price })} />
          </div>
        </div>

        <div className={styles.paramsBlock}>
          <h3>Характеристики товара</h3>

          {currentCategory === 'auto' && (
            <Row gutter={16}>
              <Col span={12}>
                <Form.Item name={['params', 'brand']} label="Марка"><Input /></Form.Item>
              </Col>
              <Col span={12}>
                <Form.Item name={['params', 'model']} label="Модель"><Input /></Form.Item>
              </Col>
              <Col span={12}>
                <Form.Item name={['params', 'yearOfManufacture']} label="Год выпуска"><InputNumber style={{width: '100%'}} /></Form.Item>
              </Col>
              <Col span={12}>
                <Form.Item name={['params', 'transmission']} label="Коробка передач">
                  <Select>
                    <Option value="automatic">Автомат</Option>
                    <Option value="manual">Механика</Option>
                  </Select>
                </Form.Item>
              </Col>
              <Col span={12}>
                <Form.Item name={['params', 'mileage']} label="Пробег (км)"><InputNumber style={{width: '100%'}} /></Form.Item>
              </Col>
              <Col span={12}>
                <Form.Item name={['params', 'enginePower']} label="Мощность двигателя (л.с.)"><InputNumber style={{width: '100%'}} /></Form.Item>
              </Col>
            </Row>
          )}

          {currentCategory === 'real_estate' && (
            <Row gutter={16}>
              <Col span={12}>
                <Form.Item name={['params', 'type']} label="Тип недвижимости">
                  <Select>
                    <Option value="flat">Квартира</Option>
                    <Option value="house">Дом</Option>
                    <Option value="room">Комната</Option>
                  </Select>
                </Form.Item>
              </Col>
              <Col span={12}>
                <Form.Item name={['params', 'area']} label="Площадь (м²)"><InputNumber style={{width: '100%'}} /></Form.Item>
              </Col>
              <Col span={12}>
                <Form.Item name={['params', 'floor']} label="Этаж"><InputNumber style={{width: '100%'}} /></Form.Item>
              </Col>
              <Col span={24}>
                <Form.Item name={['params', 'address']} label="Адрес"><Input /></Form.Item>
              </Col>
            </Row>
          )}

          {currentCategory === 'electronics' && (
            <Row gutter={16}>
              <Col span={12}>
                <Form.Item name={['params', 'type']} label="Тип электроники">
                  <Select>
                    <Option value="phone">Телефон</Option>
                    <Option value="laptop">Ноутбук</Option>
                    <Option value="misc">Прочее</Option>
                  </Select>
                </Form.Item>
              </Col>
              <Col span={12}>
                <Form.Item name={['params', 'brand']} label="Бренд"><Input /></Form.Item>
              </Col>
              <Col span={12}>
                <Form.Item name={['params', 'model']} label="Модель"><Input /></Form.Item>
              </Col>
              <Col span={12}>
                <Form.Item name={['params', 'condition']} label="Состояние">
                  <Select>
                    <Option value="new">Новое</Option>
                    <Option value="used">Б/у</Option>
                  </Select>
                </Form.Item>
              </Col>
              <Col span={12}>
                <Form.Item name={['params', 'color']} label="Цвет"><Input /></Form.Item>
              </Col>
            </Row>
          )}
        </div>

        <Form.Item label="Описание">
          <Form.Item name="description" noStyle>
            <TextArea rows={6} showCount maxLength={1000} placeholder="Подробное описание объявления" />
          </Form.Item>
          <div style={{ marginTop: 8 }}>
            <AIDescriptionButton 
              form={form} 
              isDescriptionEmpty={isDescriptionEmpty} 
              onApplyDescription={(text) => form.setFieldsValue({ description: text })} 
            />
          </div>
        </Form.Item>

        <Form.Item>
          <Space>
            <Button type="primary" htmlType="submit">
              Сохранить
            </Button>
            <Button 
              onClick={() => {
                localStorage.removeItem(draftKey);
                navigate(`/ads/${id}`);
              }}
            >
              Отменить
            </Button>
          </Space>
        </Form.Item>
      </Form>
    </Content>
  );
};

export default ItemEditPage;
